import Link from "next/link";
import styles from "./home.module.css";
import Image from 'next/image'

function Home() {
  return (
    <div className={styles.home}>

      <div className={styles.text}>
        <h2>Hakkımda</h2>
        <p>
          Merhaba ben Güngör Öztürk. Konya Teknik Üniversitesi Bilgisayar
          Mühendisliği bölümü ikinci sınıf öğrencisiyim. Konya Teknik
          Üniversitesi Bilgi işlem Daire Başkanlığında yarı zamanlı olarak
          çalışıyor, aynı zamanda mobil uygulama geliştirmekle de ilgileniyorum.
          Kullanıcıların istek ve ihtiyaçları doğrultusunda, bu ihtiyaçlara
          çözüm getirecek platformlar geliştimek istediğim için bu alanlarda
          kendimi geliştirmeye gayret ediyorum.Boş zamanlarımda hobi olarak
          müzikle ilgileniyor, klarnet,ney ve bağlama çalıyorum.{" "}
        </p>
      </div>
      
      <div className={styles.meImg}>
        <Image
          src="/me.png"
          alt="Picture of the author"
          width={300}
          height={300}
        />
      </div>
    </div>
  );
}

export default Home;
